// AI 모델 헬스체크 — 각 모델에 tiny prompt 전송, 결과 수집
const MODELS = [
  {
    "id": "groq-llama31-8b",
    "provider": "groq",
    "apiModel": "llama-3.1-8b-instant",
    "baseUrl": "https://api.groq.com/openai/v1",
    "keyEnv": "GROQ_API_KEY"
  },
  {
    "id": "cerebras-llama31-8b",
    "provider": "cerebras",
    "apiModel": "llama3.1-8b",
    "baseUrl": "https://api.cerebras.ai/v1",
    "keyEnv": "CEREBRAS_API_KEY"
  },
  {
    "id": "or-gemini-flash-lite",
    "provider": "openrouter",
    "apiModel": "google/gemini-2.0-flash-lite-001",
    "baseUrl": "https://openrouter.ai/api/v1",
    "keyEnv": "OPENROUTER_API_KEY"
  },
  {
    "id": "or-qwen3-plus",
    "provider": "openrouter",
    "apiModel": "qwen/qwen3.6-plus",
    "baseUrl": "https://openrouter.ai/api/v1",
    "keyEnv": "OPENROUTER_API_KEY"
  },
  {
    "id": "or-step-flash",
    "provider": "openrouter",
    "apiModel": "stepfun/step-3.5-flash",
    "baseUrl": "https://openrouter.ai/api/v1",
    "keyEnv": "OPENROUTER_API_KEY"
  },
  {
    "id": "or-trinity-large",
    "provider": "openrouter",
    "apiModel": "ai21/jamba-large-1.7",
    "baseUrl": "https://openrouter.ai/api/v1",
    "keyEnv": "OPENROUTER_API_KEY"
  },
  {
    "id": "or-gemini-flash-exp",
    "provider": "openrouter",
    "apiModel": "arcee-ai/trinity-large-preview:free",
    "baseUrl": "https://openrouter.ai/api/v1",
    "keyEnv": "OPENROUTER_API_KEY"
  },
  {
    "id": "or-free",
    "provider": "openrouter",
    "apiModel": "openrouter/auto",
    "baseUrl": "https://openrouter.ai/api/v1",
    "keyEnv": "OPENROUTER_API_KEY"
  }
];

const TEST_PROMPT = [{ role: 'user', content: 'Reply with exactly: ok' }];

async function testModel(m) {
  const key = $vars[m.keyEnv] || '';
  if (!key) return { modelId: m.id, status: 'error', latencyMs: null, errorMsg: 'API KEY 없음' };

  const start = Date.now();
  try {
    const res = await fetch(m.baseUrl + '/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + key,
      },
      body: JSON.stringify({
        model: m.apiModel,
        messages: TEST_PROMPT,
        max_tokens: 5,
        temperature: 0,
      }),
      signal: AbortSignal.timeout(15000),
    });
    const latencyMs = Date.now() - start;
    if (!res.ok) {
      const errText = await res.text().catch(() => res.status.toString());
      return { modelId: m.id, status: 'error', latencyMs, errorMsg: errText.slice(0, 120) };
    }
    await res.json(); // 응답 소비
    return { modelId: m.id, status: 'ok', latencyMs, errorMsg: '' };
  } catch (e) {
    return { modelId: m.id, status: 'error', latencyMs: Date.now() - start, errorMsg: String(e).slice(0, 120) };
  }
}

const checkedAt = new Date().toISOString();
const results = [];
for (const m of MODELS) {
  const r = await testModel(m);
  results.push({ json: { ...r, checkedAt } });
}
return results;

